<?php
declare(strict_types=1);
require_once __DIR__.'/includes/site-settings.php';
if(session_status()!==PHP_SESSION_ACTIVE)session_start();
if(empty($_SESSION['feedback_csrf']))$_SESSION['feedback_csrf']=bin2hex(random_bytes(32));
$pdo=db();$errors=[];$submitted=false;$form=['company_name'=>'','person_name'=>'','designation'=>'','location'=>'','email'=>'','rating'=>'5','feedback'=>''];
function publicFeedbackImageUpload(string $field): array {
    $upload=$_FILES[$field]??null;if(!is_array($upload)||($upload['error']??UPLOAD_ERR_NO_FILE)===UPLOAD_ERR_NO_FILE)return ['path'=>'','error'=>''];
    if(($upload['error']??UPLOAD_ERR_NO_FILE)!==UPLOAD_ERR_OK||(int)($upload['size']??0)>5*1024*1024||!is_uploaded_file((string)($upload['tmp_name']??'')))return ['path'=>'','error'=>'Each image must be a verified file of 5 MB or smaller.'];
    $map=['image/jpeg'=>'jpg','image/png'=>'png','image/webp'=>'webp'];$mime=(new finfo(FILEINFO_MIME_TYPE))->file((string)$upload['tmp_name']);
    if(!is_string($mime)||!isset($map[$mime])||@getimagesize((string)$upload['tmp_name'])===false)return ['path'=>'','error'=>'Upload a valid JPG, PNG, or WebP image.'];
    $dir=__DIR__.'/public/uploads/testimonials';if(!is_dir($dir))mkdir($dir,0750,true);$path='public/uploads/testimonials/'.bin2hex(random_bytes(16)).'.'.$map[$mime];
    if(!move_uploaded_file((string)$upload['tmp_name'],__DIR__.'/'.$path))return ['path'=>'','error'=>'The image could not be saved.'];return ['path'=>$path,'error'=>''];
}
if($_SERVER['REQUEST_METHOD']==='POST'){
 foreach($form as$k=>$v)$form[$k]=trim((string)($_POST[$k]??$v));
 if(!isset($_POST['csrf_token'])||!hash_equals($_SESSION['feedback_csrf'],(string)$_POST['csrf_token']))$errors[]='Your session expired. Please try again.';
 if(mb_strlen($form['company_name'])<2||mb_strlen($form['company_name'])>180)$errors[]='Enter your name or company name.';
 if($form['email']!==''&&!filter_var($form['email'],FILTER_VALIDATE_EMAIL))$errors[]='Enter a valid email address.';
 if(mb_strlen($form['feedback'])<10||mb_strlen($form['feedback'])>5000)$errors[]='Feedback must be between 10 and 5,000 characters.';
 $rating=filter_var($form['rating'],FILTER_VALIDATE_INT,['options'=>['min_range'=>1,'max_range'=>5]]);if($rating===false)$errors[]='Choose a rating.';
 $logo=publicFeedbackImageUpload('client_logo');$photo=publicFeedbackImageUpload('client_image');if($logo['error'])$errors[]=$logo['error'];if($photo['error'])$errors[]=$photo['error'];
 if(!$errors){$short=mb_strimwidth(preg_replace('/\s+/',' ',$form['feedback']),0,500,'…');$order=(int)$pdo->query('SELECT COALESCE(MAX(sort_order),0)+1 FROM testimonials')->fetchColumn();try{$pdo->prepare('INSERT INTO testimonials(client_logo,client_image,company_name,person_name,designation,location,short_feedback,full_feedback,rating,sort_order,status)VALUES(?,?,?,?,?,?,?,?,?,?,0)')->execute([$logo['path'],$photo['path'],mb_substr($form['company_name'],0,180),mb_substr($form['person_name'],0,180),mb_substr($form['designation'],0,180),mb_substr($form['location'],0,180),$short,$form['feedback'],$rating,$order]);$submitted=true;}catch(Throwable$e){foreach([$logo['path'],$photo['path']]as$path)if($path!==''&&is_file(__DIR__.'/'.$path))unlink(__DIR__.'/'.$path);throw $e;}}
}
$headerSettings=getHeaderSettings();
?><!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Give Feedback | Design24 Studio</title><link rel="stylesheet" href="assets/css/style.css"><style>.feedback-page{max-width:760px;margin:54px auto;padding:0 20px 70px}.feedback-card{padding:clamp(24px,5vw,48px);border-radius:12px;background:#fff;box-shadow:0 14px 40px rgba(6,61,46,.1)}.feedback-card h1{margin-top:0;color:#07553e}.feedback-grid{display:grid;grid-template-columns:1fr 1fr;gap:18px}.feedback-card label{display:block;margin-bottom:7px;font-weight:700}.feedback-card input,.feedback-card select,.feedback-card textarea{width:100%;padding:12px;border:1px solid #b7c4bf;border-radius:5px;font:inherit}.feedback-card textarea{min-height:150px}.feedback-card button{margin-top:24px;padding:13px 24px;border:0;border-radius:5px;background:#07553e;color:#fff;font-weight:700;cursor:pointer}.feedback-card .wide{grid-column:1/-1}.feedback-message{padding:16px;border-radius:6px;background:#edf9f4;color:#07553e}.feedback-error{padding:12px;border-radius:6px;background:#fff0f0;color:#8b1e1e}@media(max-width:600px){.feedback-grid{grid-template-columns:1fr}.feedback-card .wide{grid-column:auto}}</style></head><body class="<?=settingEnabled($headerSettings,'show_top_bar')?'has-top-bar':'no-top-bar'?>"><?php require __DIR__.'/includes/site-header.php';?><main class="feedback-page"><section class="feedback-card"><?php if($submitted):?><div class="feedback-message"><h1>Thank you for your feedback</h1><p>Your feedback has been submitted for review. Once approved, it may appear on our website.</p><a href="/testimonials">View client feedback</a></div><?php else:?><h1>Give Your Valuable Feedback</h1><p>We appreciate your experience with Design24 Studio. Your submission is reviewed before publication.</p><?php if($errors):?><div class="feedback-error"><ul><?php foreach($errors as$e):?><li><?=siteEscape($e)?></li><?php endforeach?></ul></div><?php endif?><form method="post" enctype="multipart/form-data"><input type="hidden" name="csrf_token" value="<?=siteEscape($_SESSION['feedback_csrf'])?>"><div class="feedback-grid"><div><label>Name or Company *</label><input name="company_name" maxlength="180" value="<?=siteEscape($form['company_name'])?>" required></div><div><label>Your Name</label><input name="person_name" maxlength="180" value="<?=siteEscape($form['person_name'])?>"></div><div><label>Email Address</label><input name="email" type="email" maxlength="190" value="<?=siteEscape($form['email'])?>"></div><div><label>Location</label><input name="location" maxlength="180" value="<?=siteEscape($form['location'])?>"></div><div><label>Designation</label><input name="designation" maxlength="180" value="<?=siteEscape($form['designation'])?>"></div><div><label>Rating *</label><select name="rating"><?php for($i=5;$i>=1;$i--):?><option value="<?=$i?>" <?=$form['rating']===(string)$i?'selected':''?>><?=$i?> star<?=$i===1?'':'s'?></option><?php endfor?></select></div><div><label>Company Logo</label><input name="client_logo" type="file" accept="image/jpeg,image/png,image/webp"><small>Optional: JPG, PNG, or WebP, max 5 MB.</small></div><div><label>Your Photo</label><input name="client_image" type="file" accept="image/jpeg,image/png,image/webp"><small>Optional: JPG, PNG, or WebP, max 5 MB.</small></div><div class="wide"><label>Your Feedback *</label><textarea name="feedback" maxlength="5000" required><?=siteEscape($form['feedback'])?></textarea></div></div><button>Submit feedback for review</button></form><?php endif?></section></main><?php require __DIR__.'/includes/site-footer.php';?><script src="assets/js/script.js"></script></body></html>
